 56→const val UPDATE_TAGS_THRESHOLD = 1000 * 60 * 60 // 1 hr
 57→const val TRACK_TAB_CHANGED_THROTTLE = 100L
 58→
 59→@Suppress("ForbiddenComment")
 60→class ReaderViewModel @Inject constructor(
 61→    @Named(UI_THREAD) private val mainDispatcher: CoroutineDispatcher,
 62→    @Named(BG_THREAD) private val bgDispatcher: CoroutineDispatcher,
 63→    private val appPrefsWrapper: AppPrefsWrapper,
 64→    private val dateProvider: DateProvider,
 65→    private val loadReaderTabsUseCase: LoadReaderTabsUseCase,
 66→    private val readerTracker: ReaderTracker,
 67→    private val accountStore: AccountStore,
 68→    private val quickStartRepository: QuickStartRepository,
 69→    private val selectedSiteRepository: SelectedSiteRepository,
 70→    private val jetpackBrandingUtils: JetpackBrandingUtils,
 71→    private val snackbarSequencer: SnackbarSequencer,
 72→    private val jetpackFeatureRemovalOverlayUtil: JetpackFeatureRemovalOverlayUtil,
 73→    private val readerTopBarMenuHelper: ReaderTopBarMenuHelper,
 74→    // todo: annnmarie removed this private val getFollowedTagsUseCase: GetFollowedTagsUseCase
 75→) : ScopedViewModel(mainDispatcher) {
 76→    private var initialized: Boolean = false
 77→    private var wasPaused: Boolean = false
 78→    private var trackReaderTabJob: Job? = null
 79→    private var isQuickStartPromptShown: Boolean = false
 80→
 81→    private val _uiState = MutableLiveData<ReaderUiState>()
 82→    val uiState: LiveData<ReaderUiState> = _uiState.distinct()
 83→
 84→    private val _topBarUiState = MutableLiveData<TopBarUiState>()
 85→    val topBarUiState: LiveData<TopBarUiState> = _topBarUiState.distinct()
 86→
 87→    private val _updateTags = MutableLiveData<Event<Unit>>()
 88→    val updateTags: LiveData<Event<Unit>> = _updateTags
 89→
 90→    private val _showSearch = MutableLiveData<Event<Unit>>()
 91→    val showSearch: LiveData<Event<Unit>> = _showSearch
 92→
 93→    private val _showSettings = MutableLiveData<Event<Unit>>()
 94→    val showSettings: LiveData<Event<Unit>> = _showSettings
 95→
 96→    private val _showReaderInterests = MutableLiveData<Event<Unit>>()
 97→    val showReaderInterests: LiveData<Event<Unit>> = _showReaderInterests
 98→
 99→    private val _closeReaderInterests = MutableLiveData<Event<Unit>>()
100→    val closeReaderInterests: LiveData<Event<Unit>> = _closeReaderInterests
101→
102→    private val _quickStartPromptEvent = MutableLiveData<Event<QuickStartReaderPrompt>>()
103→    val quickStartPromptEvent = _quickStartPromptEvent as LiveData<Event<QuickStartReaderPrompt>>
104→
105→    private val _showJetpackPoweredBottomSheet = MutableLiveData<Event<Boolean>>()
106→    val showJetpackPoweredBottomSheet: LiveData<Event<Boolean>> = _showJetpackPoweredBottomSheet
107→
108→    private val _showJetpackOverlay = MutableLiveData<Event<Boolean>>()
109→    val showJetpackOverlay: LiveData<Event<Boolean>> = _showJetpackOverlay
110→
111→    private var readerTagsList = ReaderTagList()
112→
113→    init {
114→        EventBus.getDefault().register(this)
115→    }
116→
117→    fun start() {
118→        if (tagsRequireUpdate()) _updateTags.value = Event(Unit)
119→        if (initialized) return
120→        loadTabs()
121→        if (jetpackBrandingUtils.shouldShowJetpackPoweredBottomSheet()) showJetpackPoweredBottomSheet()
122→    }
123→
124→    private fun showJetpackPoweredBottomSheet() {
125→//        _showJetpackPoweredBottomSheet.value = Event(true)
126→    }
127→
128→    private fun loadTabs() {
129→        launch {
130→            val currentContentUiState = _uiState.value as? ContentUiState
131→            val tagList = loadReaderTabsUseCase.loadTabs()
132→            if (tagList.isNotEmpty() && readerTagsList != tagList) {
133→                updateReaderTagsList(tagList)
134→                updateTopBarUiState()
135→                _uiState.value = ContentUiState(
136→                    tabUiStates = tagList.map { TabUiState(label = UiStringText(it.label)) },
137→                    selectedReaderTag = selectedReaderTag(),
138→                    searchMenuItemUiState = MenuItemUiState(isVisible = isSearchSupported()),
139→                    settingsMenuItemUiState = MenuItemUiState(
140→                        isVisible = isSettingsSupported(),
141→                        showQuickStartFocusPoint =
142→                        currentContentUiState?.settingsMenuItemUiState?.showQuickStartFocusPoint ?: false
143→                    )
144→                )
145→                if (!initialized) {
146→                    initialized = true
147→                }
148→            }
149→        }
150→    }
151→
152→    fun onTagChanged(selectedTag: ReaderTag?) {
153→        selectedTag?.let {
154→            trackReaderTabShownIfNecessary(it)
155→        }
156→        // Store most recently selected tab so we can restore the selection after restart
157→        appPrefsWrapper.setReaderTag(selectedTag)
158→    }
159→
160→    fun onCloseReaderInterests() {
161→        _closeReaderInterests.value = Event(Unit)
162→    }
163→
164→    fun onShowReaderInterests() {
165→        _showReaderInterests.value = Event(Unit)
166→    }
167→
168→    override fun onCleared() {
169→        super.onCleared()
170→        EventBus.getDefault().unregister(this)
171→    }
172→
173→    private fun tagsRequireUpdate(): Boolean {
174→        val lastUpdated = appPrefsWrapper.readerTagsUpdatedTimestamp
175→        val now = dateProvider.getCurrentDate().time
176→        return now - lastUpdated > UPDATE_TAGS_THRESHOLD
177→    }
178→
179→    fun updateSelectedContent(selectedTag: ReaderTag) {
180→        getMenuItemFromReaderTag(selectedTag)?.let { newSelectedMenuItem ->
181→            // Update top bar UI state so menu is updated with new selected item
