135→            return false;
136→        }
137→        String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
138→        return SqlUtils.boolForQuery(ReaderDatabase.getReadableDb(),
139→                                     "SELECT 1 FROM tbl_tags WHERE tag_slug=?1 AND tag_type=?2",
140→                                     args);
141→    }
