161→    private static ReaderTag getTagFromCursor(Cursor c) {
162→        if (c == null) {
163→            throw new IllegalArgumentException("null tag cursor");
164→        }
165→
166→        String tagSlug = c.getString(c.getColumnIndexOrThrow("tag_slug"));
167→        String tagDisplayName = c.getString(c.getColumnIndexOrThrow("tag_display_name"));
168→        String tagTitle = c.getString(c.getColumnIndexOrThrow("tag_title"));
169→        String endpoint = c.getString(c.getColumnIndexOrThrow("endpoint"));
170→        ReaderTagType tagType = ReaderTagType.fromInt(c.getInt(c.getColumnIndexOrThrow("tag_type")));
171→
172→        return new ReaderTag(tagSlug, tagDisplayName, tagTitle, endpoint, tagType);
173→    }
