175→    public static ReaderTag getTag(String tagSlug, ReaderTagType tagType) {
176→        if (TextUtils.isEmpty(tagSlug)) {
177→            return null;
178→        }
179→
180→        String[] args = {tagSlug, Integer.toString(tagType.toInt())};
181→        Cursor c = ReaderDatabase.getReadableDb()
182→                                 .rawQuery("SELECT * FROM tbl_tags WHERE tag_slug=? AND tag_type=? LIMIT 1", args);
183→        try {
184→            if (!c.moveToFirst()) {
185→                return null;
186→            }
187→            return getTagFromCursor(c);
188→        } finally {
189→            SqlUtils.closeCursor(c);
190→        }
191→    }
