198→        String[] args = {"%" + endpoint};
199→        String query = "SELECT * FROM tbl_tags WHERE endpoint LIKE ? LIMIT 1";
200→        Cursor cursor = ReaderDatabase.getReadableDb().rawQuery(query, args);
