288→    public static void deleteTags(ReaderTagList tagList) {
289→        if (tagList == null || tagList.size() == 0) {
290→            return;
291→        }
292→
293→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
294→        db.beginTransaction();
295→        try {
296→            for (ReaderTag tag : tagList) {
297→                String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
298→                ReaderDatabase.getWritableDb().delete("tbl_tags", "tag_slug=? AND tag_type=?", args);
