343→    /*
344→     * determine whether the passed tag should be auto-updated based on when it was last updated
345→     */
346→    public static boolean shouldAutoUpdateTag(ReaderTag tag) {
347→        int minutes = minutesSinceLastUpdate(tag);
348→        if (minutes == NEVER_UPDATED) {
349→            return true;
350→        }
351→        return (minutes >= ReaderConstants.READER_AUTO_UPDATE_DELAY_MINUTES);
352→    }
353→
354→    private static final int NEVER_UPDATED = -1;
355→
356→    private static int minutesSinceLastUpdate(ReaderTag tag) {
357→        if (tag == null) {
358→            return 0;
359→        }
360→
361→        String updated = getTagLastUpdated(tag);
362→        if (TextUtils.isEmpty(updated)) {
363→            return NEVER_UPDATED;
364→        }
365→
366→        Date dtUpdated = DateTimeUtils.dateFromIso8601(updated);
367→        if (dtUpdated == null) {
368→            return 0;
369→        }
370→
371→        Date dtNow = new Date();
372→        return DateTimeUtils.minutesBetween(dtUpdated, dtNow);
373→    }
374→}
