402→    private static boolean defaultTagFoundAndAdded(
403→            Map<String, TagInfo> defaultTagInfos,
404→            ReaderTag tag,
405→            Map<String, ReaderTag> defaultTags
406→    ) {
407→        boolean foundAndAdded = false;
408→
409→        for (String key : defaultTagInfos.keySet()) {
410→            if (defaultTagInfos.get(key).isDesiredTag(tag)) {
411→                if (putIfAbsentDone(defaultTags, key, tag)) {
412→                    foundAndAdded = true;
413→                }
414→                break;
415→            }
416→        }
417→
418→        return foundAndAdded;
419→    }
