421→    public static ReaderTagList getOrderedTagsList(ReaderTagList tagList, Map<String, TagInfo> defaultTagInfos) {
422→        ReaderTagList orderedTagList = new ReaderTagList();
423→        Map<String, ReaderTag> defaultTags = new HashMap<>();
424→
425→        for (ReaderTag tag : tagList) {
426→            if (defaultTagFoundAndAdded(defaultTagInfos, tag, defaultTags)) continue;
427→
428→            orderedTagList.add(tag);
429→        }
430→        prependDefaults(defaultTags, orderedTagList, defaultTagInfos);
431→
432→        return orderedTagList;
433→    }
