435→    public static boolean isTagManagedInFollowingTab(
436→            ReaderTag tag,
437→            boolean isTopLevelReader,
438→            FilteredRecyclerView recyclerView
439→    ) {
440→        if (isTopLevelReader) {
441→            if (ReaderUtils.isDefaultInMemoryTag(tag)) {
442→                return true;
443→            }
444→
445→            boolean isSpecialTag = tag != null
446→                                   &&
447→                                   (tag.isDiscover() || tag.isPostsILike() || tag.isBookmarked());
448→
449→            boolean tabsInitializingNow = recyclerView != null && recyclerView.getCurrentFilter() == null;
450→
451→            boolean tagIsFollowedSitesOrAFollowedTag = tag != null
452→                                                       && (
453→                                                               tag.isFollowedSites()
454→                                                               || tag.tagType == ReaderTagType.FOLLOWED
455→                                                       );
456→
457→            if (isSpecialTag) {
458→                return false;
459→            } else if (tabsInitializingNow) {
460→                return tagIsFollowedSitesOrAFollowedTag;
461→            } else if (recyclerView != null && recyclerView.getCurrentFilter() instanceof ReaderTag) {
462→                if (recyclerView.isValidFilter(tag)) {
463→                    return tag.isFollowedSites();
464→                } else {
465→                    // If we reach here it means we are setting a followed tag or site in the Following tab
466→                    return true;
467→                }
468→            } else {
469→                return false;
470→            }
471→        } else {
472→            return tag != null && tag.isFollowedSites();
473→        }
474→    }
