480→            @NonNull ReaderTag defaultTag
481→    ) {
482→        if (!isTopLevelReader) {
483→            return tag;
484→        }
485→
486→        boolean isValidFilter = (recyclerView != null && recyclerView.isValidFilter(tag));
487→        boolean isSpecialTag = tag.isDiscover() || tag.isPostsILike() || tag.isBookmarked();
488→        if (!isSpecialTag && !isValidFilter && isTagManagedInFollowingTab(tag, isTopLevelReader, recyclerView)) {
489→            return defaultTag;
490→        }
491→
492→        return tag;
493→    }
