class ReaderTopBarMenuHelperP2Test {
    private val helper = ReaderTopBarMenuHelper()

    @Test
    fun `GIVEN p2 tag is available WHEN createMenu THEN p2 item is created correctly`() {
        val tags = ReaderTagList().apply {
            add(mockP2Tag()) // item 0
        }

        val menu = helper.createMenu(tags)

        val p2Item = menu.findSingleItem { it.id == "0" }!!
        assertThat(p2Item.text).isEqualTo(UiStringRes(R.string.reader_dropdown_menu_p2))
    }

    private fun List<MenuElementData>.findSingleItem(
        predicate: (MenuElementData.Item.Single) -> Boolean
    ): MenuElementData.Item.Single? {
        return find { it is MenuElementData.Item.Single && predicate(it) } as? MenuElementData.Item.Single
    }

    private fun mockP2Tag(): ReaderTag {
        return mock {
            on { isP2 } doReturn true
        }
    }
}
