383→    private static void prependDefaults(
384→            Map<String, ReaderTag> defaultTags,
385→            ReaderTagList orderedTagList,
386→            Map<String, TagInfo> defaultTagInfo
387→    ) {
388→        if (defaultTags.isEmpty()) return;
389→
390→        List<String> reverseOrderedKeys = new ArrayList<>(defaultTagInfo.keySet());
391→        Collections.reverse(reverseOrderedKeys);
392→
393→        for (String key : reverseOrderedKeys) {
394→            if (defaultTags.containsKey(key)) {
395→                ReaderTag tag = defaultTags.get(key);
396→
397→                orderedTagList.add(0, tag);
398→            }
399→        }
400→    }
